/// <summary>
/// Extensión del método <c>init</c> para el modelo ETGSPAIN.
/// </summary>
/// <remarks>Este código se utiliza para mostrar u ocultar características en empresas españolas.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(InventValueProcess, InventValueReportTmpLine_ETGSPAINPurchOperationName)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(InventValueProcess, InventValueReportTmpLine_ETGSPAINInventLocationAdressCity)).visible(currentCompanyIsSpanishCompany);
}
